#include <stdio.h>

struct Enemy {
    int hp;
    int damage;
};

int main() {
    // Create an army of 3 enemies
    struct Enemy army[3];

    // Accessing an individual enemy's stats
    army[0].hp = 50;
    army[1].hp = 100;
    army[2].hp = 200;

    printf("Enemy 2 has %d HP!\n", army[1].hp);
    return 0;
}

#include <stdio.h>

struct Player {
    char* name; // Pointer-based string (advanced!)
    int hp;
};

int main() {
    // Initialize directly in order: name, then hp
    struct Player p1 = {"Bob", 50};

    printf("%s: %d HP\n", p1.name, p1.hp);
    return 0;
}
